164→function isClipboardRowArray(v: unknown): v is ClipboardEntryRow[] {
165→  if (!Array.isArray(v)) return false;
166→  return v.every(
167→    r =>
168→      typeof r === 'object' &&
169→      r !== null &&
170→      'id' in r &&
171→      typeof r.id === 'string' &&
172→      'content' in r &&
173→      typeof r.content === 'string' &&
174→      'copied_at' in r &&
175→      typeof r.copied_at === 'string',
176→  );
177→}
