233→export const clipboardDb = {
234→  async getAll(limit = 1000): Promise<ClipboardEntryRow[]> {
235→    if (isTauri) {
236→      const db = await getDb();
237→      return db.select<ClipboardEntryRow[]>(
238→        'SELECT id, content, content_type, source_app, copied_at, pinned FROM clipboard_entries ORDER BY pinned DESC, copied_at DESC LIMIT $1',
239→        [limit],
240→      );
241→    }
242→    return storageGet('clipboard-history', isClipboardRowArray) ?? [];
243→  },
244→  async insert(entry: ClipboardEntryRow): Promise<void> {
245→    if (isTauri) {
246→      const db = await getDb();
247→      await db.execute(
248→        'INSERT INTO clipboard_entries (id, content, content_type, source_app, copied_at, pinned) VALUES ($1, $2, $3, $4, $5, $6)',
249→        [
250→          entry.id,
251→          entry.content,
252→          entry.content_type,
253→          entry.source_app,
254→          entry.copied_at,
255→          entry.pinned,
256→        ],
257→      );
258→      return;
259→    }
260→    const all = await this.getAll();
261→    all.unshift(entry);
262→    storageSet('clipboard-history', all);
263→  },
264→  async update(
265→    id: string,
266→    updates: Partial<Omit<ClipboardEntryRow, 'id'>>,
267→  ): Promise<void> {
268→    if (isTauri) {
269→      const db = await getDb();
270→      const query = buildUpdateQuery(
271→        'clipboard_entries',
272→        updates,
273→        CLIPBOARD_COLUMNS,
274→        id,
275→      );
276→      if (!query) return;
277→      await db.execute(query.sql, query.values);
278→      return;
279→    }
280→    const all = await this.getAll();
281→    const updated = all.map(r =>
282→      r.id === id
283→        ? {
284→            ...r,
285→            ...updates,
286→          }
287→        : r);
288→    storageSet('clipboard-history', updated);
289→  },
290→  async delete(id: string): Promise<void> {
291→    if (isTauri) {
292→      const db = await getDb();
293→      await db.execute('DELETE FROM clipboard_entries WHERE id = $1', [id]);
294→      return;
295→    }
296→    const all = await this.getAll();
297→    storageSet(
298→      'clipboard-history',
299→      all.filter(r => r.id !== id),
300→    );
301→  },
302→  async clear(): Promise<void> {
303→    if (isTauri) {
304→      const db = await getDb();
305→      await db.execute('DELETE FROM clipboard_entries');
306→      return;
307→    }
308→    storageRemove('clipboard-history');
309→  },
310→  async search(query: string, limit = 50): Promise<ClipboardEntryRow[]> {
311→    if (isTauri) {
312→      const escaped = escapeFts5Query(query);
313→      if (!escaped) return [];
314→      const db = await getDb();
315→      return db.select<ClipboardEntryRow[]>(
316→        `SELECT ce.id, ce.content, ce.content_type, ce.source_app, ce.copied_at, ce.pinned
317→         FROM clipboard_entries ce
318→         JOIN clipboard_entries_fts fts ON ce.rowid = fts.rowid
319→         WHERE clipboard_entries_fts MATCH $1
320→         ORDER BY ce.pinned DESC, ce.copied_at DESC
321→         LIMIT $2`,
322→        [
323→          escaped,
324→          limit,
325→        ],
326→      );
327→    }
328→    const all = await this.getAll();
329→    const q = query.toLowerCase();
330→    return all.filter(r => r.content.toLowerCase().includes(q)).slice(0, limit);
331→  },
332→};
