630→export const recentCommandDb = {
631→  async getAll(limit = 10): Promise<string[]> {
632→    if (isTauri) {
633→      const db = await getDb();
634→      const rows = await db.select<Pick<RecentCommandRow, 'command_id'>[]>(
635→        'SELECT command_id FROM recent_commands ORDER BY used_at DESC LIMIT $1',
636→        [limit],
637→      );
638→      return rows.map(r => r.command_id);
639→    }
640→    const stored = storageGet('recent-commands', isStringArray);
641→    return stored?.slice(0, limit) ?? [];
642→  },
643→  async add(commandId: string): Promise<void> {
644→    if (isTauri) {
645→      const db = await getDb();
646→      await db.execute('DELETE FROM recent_commands WHERE command_id = $1', [
647→        commandId,
648→      ]);
649→      await db.execute('INSERT INTO recent_commands (command_id) VALUES ($1)', [
650→        commandId,
651→      ]);
652→      await db.execute(
653→        `DELETE FROM recent_commands WHERE id NOT IN (
654→          SELECT id FROM recent_commands ORDER BY used_at DESC LIMIT 10
655→        )`,
656→      );
657→      return;
658→    }
659→    const all = await this.getAll();
660→    const next = [
661→      commandId,
662→      ...all.filter(id => id !== commandId),
663→    ].slice(0, 10);
664→    storageSet('recent-commands', next);
665→  },
666→  async clear(): Promise<void> {
667→    if (isTauri) {
668→      const db = await getDb();
669→      await db.execute('DELETE FROM recent_commands');
670→      return;
671→    }
672→    storageRemove('recent-commands');
673→  },
674→};
