141→function entryToRow(entry: SnippetEntry): SnippetRow {
142→  return {
143→    id: entry.id,
144→    name: entry.name,
145→    keyword: entry.keyword,
146→    content: entry.content,
147→    category: entry.category,
148→    tags: JSON.stringify(entry.tags),
149→    created_at: entry.createdAt.toISOString(),
150→  };
151→}
