753→  if (subView !== 'list') {
754→    const formTitle = subView === 'edit' ? 'Edit Snippet' : 'Create Snippet';
755→    return (
756→      <>
757→        <SearchBar
758→          value=""
759→          onChange={() => {}}
760→          placeholder={formTitle}
761→          breadcrumbs={[
762→            ...nav.breadcrumbs,
763→            {
764→              label: 'Snippets',
765→              onBack: handleEscape,
766→            },
767→          ]}
768→        />
769→        <div className="command-palette__body">
770→          <div className="command-palette__list-container">
771→            <EditSnippetView
772→              snippet={subView === 'edit' ? editingSnippet : undefined}
773→              onSubmit={handleFormSubmit}
774→            />
775→          </div>
776→        </div>
777→        <ActionPanel
778→          contextLabel={formTitle}
779→          actions={[
780→            {
781→              label: 'Submit',
782→              shortcut: (
783→                <Kbd
784→                  keys={[
785→                    '⌘',
786→                    '↵',
787→                  ]}
788→                />
789→              ),
790→            },
791→          ]}
792→          dropdownOpen={false}
793→          dropdownSections={[]}
794→          onDropdownClose={() => {}}
795→        />
796→        <HUDContainer items={hudItems} />
797→      </>
798→    );
799→  }
800→
801→  return (
802→    <>
803→      <SearchBar
804→        value={query}
805→        onChange={handleQueryChange}
806→        placeholder="Search Snippets..."
807→        activeDescendantId={activeDescendantId}
808→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
809→        dropdown={
810→          <SearchDropdown
811→            sections={FILTER_SECTIONS}
812→            value={filterValue}
813→            onChange={handleFilterChange}
814→          />
815→        }
816→      />
817→      <div className="command-palette__body">
818→        <div className="command-palette__list-container">
819→          {totalItemCount === 0 ? (
820→            <EmptyState
821→              icon={<SearchEmptyIcon />}
822→              title="No Snippets"
823→              description={
824→                query
825→                  ? 'Try a different search term'
826→                  : 'Create your first snippet with ⌘N'
827→              }
828→            />
829→          ) : (
830→            <List
831→              itemCount={totalItemCount}
832→              onActiveIndexChange={handleActiveIndexChange}
833→              onAction={handleInsert}
834→            >
835→              {(() => {
836→                let globalIndex = 0;
837→                const sections: ReactNode[] = [];
838→
839→                for (const group of groupedByCategory) {
840→                  sections.push(
841→                    <ListSection key={group.title} title={group.title}>
842→                      {group.items.map(entry => {
843→                        const idx = globalIndex++;
844→                        return (
845→                          <ListItem
846→                            key={entry.id}
847→                            index={idx}
848→                            icon={<SnippetHUDIcon />}
849→                            title={entry.name}
850→                            subtitle={truncateContent(entry.content, 50)}
851→                            accessories={[
852→                              ...(entry.keyword
853→                                ? [
854→                                    {
855→                                      tag: {
856→                                        text: entry.keyword,
857→                                        color: 'purple' as const,
858→                                      },
859→                                    },
860→                                  ]
861→                                : []),
862→                              ...entry.tags.map(t => ({
863→                                tag: {
864→                                  text: t.text,
865→                                  color: t.color,
866→                                },
867→                              })),
868→                              {
869→                                text: formatRelativeDate(entry.createdAt, now),
870→                                tooltip: entry.createdAt.toLocaleString(),
871→                              },
872→                            ]}
873→                            query={query || undefined}
874→                          />
875→                        );
876→                      })}
877→                    </ListSection>,
878→                  );
879→                }
880→
881→                return sections;
882→              })()}
883→            </List>
884→          )}
885→        </div>
886→      </div>
887→      <ActionPanel
888→        contextLabel="Snippets"
889→        actions={[
890→          {
891→            label: 'Insert',
892→            shortcut: <Kbd keys={['↵']} />,
893→          },
894→          {
895→            label: 'Actions',
896→            shortcut: (
897→              <Kbd
898→                keys={[
899→                  '⌘',
900→                  'K',
901→                ]}
902→              />
903→            ),
904→            onClick: toggleActions,
905→          },
906→        ]}
907→        dropdownOpen={actionsOpen}
908→        dropdownSections={dropdownSections}
909→        onDropdownClose={closeActions}
910→      />
911→      {alertState && (
912→        <Alert
913→          title={alertState.title}
914→          message={alertState.message}
915→          icon={alertState.icon}
916→          primaryAction={alertState.primaryAction}
917→          dismissAction={alertState.dismissAction}
918→          onDismiss={dismissAlert}
919→        />
920→      )}
921→      <HUDContainer items={hudItems} />
922→    </>
923→  );
