### Data Loading Pattern (lines 331-358)
```typescript
useEffect(() => {
  let aborted = false;

  snippetDb.getAll()
    .then(rows => {
      if (aborted) return;
      if (rows.length > 0) {
        setEntries(rows.map(rowToEntry));  // Convert DB rows to UI entries
      } else if (!isTauri) {
        // Mock data fallback for dev
        const mock = MOCK_SNIPPET_ENTRIES.map(e => ({ ...e }));
        setEntries(mock);
        Promise.all(mock.map(e => snippetDb.insert(entryToRow(e)))).catch(console.error);
      }
    })
    .catch(err => {
      console.error('Failed to load snippets:', err);
      if (!isTauri && !aborted) {
        setEntries(MOCK_SNIPPET_ENTRIES.map(e => ({ ...e })));
      }
    });

  return () => {
    aborted = true;  // Cancel pending operations
  };
}, []);
```

### Filtering & Grouping Pattern (lines 367-416)
```typescript
const filtered = useMemo(() => {
  let items = ftsResults ?? entries;

  // Apply category filter
  if (filterValue !== 'all') {
    items = items.filter(e => e.category === filterValue);
  }

  // Fallback to fuzzy search if no FTS results
  if (!ftsResults && query) {
    items = items.filter(e =>
      fuzzyMatch(query, e.name) ||
      fuzzyMatch(query, e.keyword) ||
      fuzzyMatch(query, e.content)
    );
  }
  return items;
}, [entries, query, filterValue, ftsResults]);

// Group by category
const groupedByCategory = useMemo(() => {
  const groups: { title: string; items: SnippetEntry[] }[] = [];
  const categoryOrder = ['code', 'email', 'template', 'general'] as const;

  for (const cat of categoryOrder) {
    const items = filtered.filter(e => e.category === cat);
    if (items.length > 0) {
      groups.push({ title: categoryLabels[cat]!, items });
    }
  }
  return groups;
}, [filtered]);
```

